+#[test]
+fn doctor_json_matches_golden() {
+    let test_home = tempfile::tempdir().expect("create temp home");
+    let scrubbed =
+        capture_robot_json(test_home.path(), &["doctor", "--json"], ExpectStatus::ExitOk);
+    assert_golden("robot/doctor.json.golden", &scrubbed);
+}
